import React from 'react';
import { Routes, Route, Navigate, useNavigate } from 'react-router-dom';

import WorkflowContainer from '../components/WorkflowContainer';
import UploadStep from '../steps/uploadStep';
import DesignStep from '../steps/designStep';
import PreviewStep from '../steps/previewStage';
import DetailsStep from '../steps/detailsStep';
import DownloadStep from '../steps/downloadStep';
import { useWorkflow } from '../store/workflowContext';

const WorkflowPage = () => {
  const nav = useNavigate();
  const { manuscriptFiles, design, setDesign } = useWorkflow();

  // ----- STEP 1: Upload -----
  // You can go forward as soon as at least one file is uploaded
  const canProceedUpload = manuscriptFiles && manuscriptFiles.length > 0;

  // ----- STEP 2: Design (internal mini-wizard) -----
  // Move forward inside the Design step
  const handleDesignNext = () => {
    if (!design) return;

    if (design.stage === 'typography') {
      // Typography -> Layout
      setDesign({ ...design, stage: 'layout' });
      return;
    }

    if (design.stage === 'layout') {
      // Layout -> Trim
      setDesign({ ...design, stage: 'trim' });
      return;
    }

    if (design.stage === 'trim') {
      // Trim -> Summary
      setDesign({ ...design, stage: 'summary' });
      return;
    }

    // If we're already on summary, go to Preview route
    if (design.stage === 'summary') {
      nav('/workflow/preview');
    }
  };

  // Move backward inside the Design step
  const handleDesignPrevious = () => {
    if (!design) {
      nav('/workflow/start');
      return;
    }

    if (design.stage === 'summary') {
      // Summary -> Trim
      setDesign({ ...design, stage: 'trim' });
      return;
    }

    if (design.stage === 'trim') {
      // Trim -> Layout
      setDesign({ ...design, stage: 'layout' });
      return;
    }

    if (design.stage === 'layout') {
      // Layout -> Typography
      setDesign({ ...design, stage: 'typography' });
      return;
    }

    // If we're on Typography, go back to Upload step
    if (design.stage === 'typography') {
      nav('/workflow/start');
    }
  };

  // Continue is always clickable on Design (inner step controls progression)
  const canProceedDesign = true;

  return (
    <Routes>
      {/* Upload & Organize */}
      <Route
        path="start"
        element={
          <WorkflowContainer
            title="Upload & Organize"
            description="Upload your manuscript files and organize them for formatting"
            step={1}
            hideNext={false}              // always show Continue
            canProceed={canProceedUpload}  // enabled once a file exists
            disableSavePrompt={true}       // no save modal on upload
          >
            <UploadStep />
          </WorkflowContainer>
        }
      />

      {/* Design (typography -> layout -> trim -> summary) */}
      <Route
        path="design"
        element={
          <WorkflowContainer
            title="Design Your Book"
            description="Customize typography, layout, and format with AI-powered recommendations"
            step={2}
            canProceed={canProceedDesign}
            onNext={handleDesignNext}
            onPrevious={handleDesignPrevious}
          >
            <DesignStep />
          </WorkflowContainer>
        }
      />

      {/* Preview */}
      <Route
        path="preview"
        element={
          <WorkflowContainer
            title="Preview"
            description="Check how pages will look with your chosen design"
            step={3}
            canProceed={true}
          >
            <PreviewStep />
          </WorkflowContainer>
        }
      />

      {/* Details */}
      <Route
        path="details"
        element={
          <WorkflowContainer
            title="Details"
            description="Add book metadata and publishing options"
            step={4}
            canProceed={true}
          >
            <DetailsStep />
          </WorkflowContainer>
        }
      />

      {/* Download */}
      <Route
        path="download"
        element={
          <WorkflowContainer
            title="Download"
            description="Download formatted files and upload packages"
            step={5}
            canProceed={true}
          >
            <DownloadStep />
          </WorkflowContainer>
        }
      />

      {/* /workflow should redirect to /workflow/start */}
      <Route index element={<Navigate to="start" replace />} />
    </Routes>
  );
};

export default WorkflowPage;
